record.field:
if env.context.get('skip_claimant_share_rebalance'): pass
else:
    old_values = env.context.get('old_values') or {}

    def _write(lines, vals):
        lines.with_context(skip_claimant_share_rebalance=True).write(vals)

    def _adjust_manual(adjust_line, manual_total):
        other_total = manual_total - adjust_line.x_share
        new_val = max(0.0, 100.0 - other_total)
        _write(adjust_line, {'x_share': new_val})
        return other_total + new_val

    def _rebalance(record, adjust_line=None):
        lines = record.x_claimant_parent_id.x_claimants_line_ids
        manual_lines = lines.filtered('x_share_is_manual')
        auto_lines = lines - manual_lines
        manual_total = sum(manual_lines.mapped('x_share'))

        if manual_lines and manual_total > 100.0: manual_total = _adjust_manual(adjust_line, manual_total)

        if auto_lines:
            remaining = max(0.0, 100.0 - manual_total)
            _write(auto_lines, {'x_share': remaining / len(auto_lines)})
            return

        if manual_lines and 100.0 - manual_total > 0: _adjust_manual(adjust_line, manual_total)

    for line in records:
        if line.x_share < 0: raise UserError('you can not add a nagative value in claimant share as percentage')
        if 'x_share' in old_values.get(line.id, {}): _write(line, {'x_share_is_manual': True})
    _rebalance(record, line)
